// ── Add Product Form ─────────────────────────────────────────────────────────
const CATEGORIES = ["Dress", "Top", "Skirt", "Pants", "Jacket", "Accessories"];
const SIZES = ["XS", "S", "M", "L", "XL", "XXL"];
const COLORS_DEFAULT = ["Black", "White", "Red", "Blue", "Green", "Pink", "Yellow", "Coral", "Navy", "Mint"];

function AddProductTab() {
  const [form, setForm] = useState({
    name: "", category: "", price: "", description: "",
    material: "", care: "", stock: "",
    sizes: [], colors: [],
  });
  const [customColor, setCustomColor] = useState("");
  const [submitted, setSubmitted] = useState(false);
  const [errors, setErrors] = useState({});

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const toggleArr = (k, val) =>
    setForm(f => ({
      ...f,
      [k]: f[k].includes(val) ? f[k].filter(x => x !== val) : [...f[k], val],
    }));

  const addCustomColor = () => {
    const c = customColor.trim();
    if (c && !form.colors.includes(c)) {
      setForm(f => ({ ...f, colors: [...f.colors, c] }));
      setCustomColor("");
    }
  };

  const validate = () => {
    const e = {};
    if (!form.name.trim()) e.name = "Required";
    if (!form.category) e.category = "Required";
    if (!form.price || isNaN(Number(form.price))) e.price = "Valid price required";
    if (!form.description.trim()) e.description = "Required";
    if (form.sizes.length === 0) e.sizes = "Select at least one";
    if (form.colors.length === 0) e.colors = "Select at least one";
    return e;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const e2 = validate();
    if (Object.keys(e2).length) { setErrors(e2); return; }
    setErrors({});
    // TODO: POST to API
    console.log("Product payload:", form);
    setSubmitted(true);
    setTimeout(() => {
      setSubmitted(false);
      setForm({ name:"",category:"",price:"",description:"",material:"",care:"",stock:"",sizes:[],colors:[] });
    }, 2500);
  };

  return (
    <div className="ad-tab-content">
      <div className="ad-tab-header">
        <div>
          <h2>Add New Product</h2>
          <p>Fill in the details below to list a new item in the store.</p>
        </div>
      </div>

      {submitted && (
        <div className="ad-success">
          <Icon d={ICO.check} /> Product added successfully!
        </div>
      )}

      <form className="ad-product-form" onSubmit={handleSubmit} noValidate>
        {/* Row 1 */}
        <div className="ad-form-grid two-col">
          <div className="ad-field">
            <label>Product Name <span className="ad-req">*</span></label>
            <input value={form.name} onChange={e => set("name", e.target.value)}
              placeholder="e.g. Tropical Breeze Dress" className={errors.name ? "err" : ""} />
            {errors.name && <span className="ad-err">{errors.name}</span>}
          </div>
          <div className="ad-field">
            <label>Category <span className="ad-req">*</span></label>
            <select value={form.category} onChange={e => set("category", e.target.value)}
              className={errors.category ? "err" : ""}>
              <option value="">Select category…</option>
              {CATEGORIES.map(c => <option key={c}>{c}</option>)}
            </select>
            {errors.category && <span className="ad-err">{errors.category}</span>}
          </div>
        </div>

        {/* Row 2 */}
        <div className="ad-form-grid two-col">
          <div className="ad-field">
            <label>Price ($) <span className="ad-req">*</span></label>
            <input type="number" min="0" step="0.01" value={form.price}
              onChange={e => set("price", e.target.value)}
              placeholder="0.00" className={errors.price ? "err" : ""} />
            {errors.price && <span className="ad-err">{errors.price}</span>}
          </div>
          <div className="ad-field">
            <label>Stock Quantity</label>
            <input type="number" min="0" value={form.stock}
              onChange={e => set("stock", e.target.value)} placeholder="e.g. 50" />
          </div>
        </div>

        {/* Description */}
        <div className="ad-field">
          <label>Description <span className="ad-req">*</span></label>
          <textarea rows={3} value={form.description}
            onChange={e => set("description", e.target.value)}
            placeholder="Describe the product…"
            className={errors.description ? "err" : ""} />
          {errors.description && <span className="ad-err">{errors.description}</span>}
        </div>

        {/* Row 3 */}
        <div className="ad-form-grid two-col">
          <div className="ad-field">
            <label>Material</label>
            <input value={form.material} onChange={e => set("material", e.target.value)}
              placeholder="e.g. 100% Organic Cotton" />
          </div>
          <div className="ad-field">
            <label>Care Instructions</label>
            <input value={form.care} onChange={e => set("care", e.target.value)}
              placeholder="e.g. Machine wash cold" />
          </div>
        </div>

        {/* Sizes */}
        <div className="ad-field">
          <label>Sizes <span className="ad-req">*</span></label>
          <div className="ad-chip-group">
            {SIZES.map(s => (
              <button type="button" key={s}
                className={`ad-chip ${form.sizes.includes(s) ? "active" : ""}`}
                onClick={() => toggleArr("sizes", s)}>
                {s}
              </button>
            ))}
          </div>
          {errors.sizes && <span className="ad-err">{errors.sizes}</span>}
        </div>

        {/* Colors */}
        <div className="ad-field">
          <label>Colors <span className="ad-req">*</span></label>
          <div className="ad-chip-group">
            {[...COLORS_DEFAULT, ...form.colors.filter(c => !COLORS_DEFAULT.includes(c))].map(c => (
              <button type="button" key={c}
                className={`ad-chip ${form.colors.includes(c) ? "active" : ""}`}
                onClick={() => toggleArr("colors", c)}>
                {c}
              </button>
            ))}
          </div>
          <div className="ad-custom-color">
            <input value={customColor} onChange={e => setCustomColor(e.target.value)}
              onKeyDown={e => e.key === "Enter" && (e.preventDefault(), addCustomColor())}
              placeholder="Add custom color…" />
            <button type="button" className="ad-add-color-btn" onClick={addCustomColor}>Add</button>
          </div>
          {errors.colors && <span className="ad-err">{errors.colors}</span>}
        </div>

        {/* Image Upload placeholder */}
        <div className="ad-field">
          <label>Product Images</label>
          <div className="ad-dropzone">
            <Icon d={ICO.image} size={28} />
            <span>Drag & drop images here, or <u>browse</u></span>
            <small>JPG, PNG up to 10MB each</small>
          </div>
        </div>

        <div className="ad-form-actions">
          <button type="button" className="ad-btn-secondary"
            onClick={() => setForm({ name:"",category:"",price:"",description:"",material:"",care:"",stock:"",sizes:[],colors:[] })}>
            Clear
          </button>
          <button type="submit" className="ad-btn-primary">
            <Icon d={ICO.product} size={15} /> Add Product
          </button>
        </div>
      </form>
    </div>
  );
}

// ── Users Tab ────────────────────────────────────────────────────────────────
function UsersTab({ users, loadingUsers, loadUsers, makeAdmin, error }) {
  return (
    <div className="ad-tab-content">
      <div className="ad-tab-header">
        <div>
          <h2>User Management</h2>
          <p>View and manage all registered users.</p>
        </div>
        <button className="ad-btn-secondary ad-refresh-btn"
          onClick={loadUsers} disabled={loadingUsers}>
          <Icon d={ICO.refresh} size={15} />
          {loadingUsers ? "Refreshing…" : "Refresh"}
        </button>
      </div>

      {error && (
        <div className="ad-alert">
          <Icon d={ICO.alert} size={15} /> {error}
        </div>
      )}

      {loadingUsers ? (
        <div className="ad-loading-rows">
          {[1,2,3].map(i => <div key={i} className="ad-skeleton-row" />)}
        </div>
      ) : users.length === 0 ? (
        <div className="ad-empty">No users found.</div>
      ) : (
        <div className="ad-table-wrap">
          <table className="ad-table">
            <thead>
              <tr>
                <th>#</th>
                <th>Name</th>
                <th>Email</th>
                <th>Role</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {users.map((u, i) => (
                <tr key={u._id || u.id}>
                  <td className="ad-idx">{i + 1}</td>
                  <td>{u.firstName} {u.lastName}</td>
                  <td className="ad-email">{u.email}</td>
                  <td>
                    <span className={`ad-pill ${u.role === "admin" ? "pill-admin" : ""}`}>
                      {u.role || "user"}
                    </span>
                  </td>
                  <td>
                    {u.role === "admin" ? (
                      <span className="ad-already-admin">Admin</span>
                    ) : (
                      <button className="ad-promote-btn"
                        onClick={() => makeAdmin(u._id || u.id)}>
                        Make Admin
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

